#include <stdio.h>
int main() {
    int T, n, i, h, d, sum, diff;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        sum = 0;
        diff = 0;
        int hArray[n], dArray[n];
        for (i = 0; i < n; i++) {
            scanf("%d", &hArray[i]);
        }
        for (i = 0; i < n; i++) {
            scanf("%d", &dArray[i]);
            diff += dArray[i] - hArray[i];
        }
        if (diff != 0) {
            printf("-1\n");
        } else {
            sum = 0;
            for (i = 0; i < n; i++) {
                sum += (hArray[i] - dArray[i]) > 0 ? (hArray[i] - dArray[i]) : 0;
            }
            printf("%d\n", sum);
        }
    }
    return 0;
}

