code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int sum = 0;
            int[] h = new int[n];
            int[] d = new int[n];
            for (int i = 0; i < n; i++) {
                h[i] = sc.nextInt();
            }
            int diff = 0;
            for (int i = 0; i < n; i++) {
                d[i] = sc.nextInt();
                diff += d[i] - h[i];
            }
            if (diff != 0) {
                System.out.println(-1);
            } else {
                sum = 0;
                for (int i = 0; i < n; i++) {
                    sum += Math.max(h[i] - d[i], 0);
                }
                System.out.println(sum);
            }
        }
    }
}

